// ─── BATCH MANAGEMENT ─────────────────────────────────────────────────────────
export const AdminBatches = () => {
  const [batches, setBatches]       = useState([]);
  const [depts, setDepts]           = useState([]);
  const [allStudents, setAllStudents] = useState([]);
  const [allCourses, setAllCourses] = useState([]);
  const [loading, setLoading]       = useState(false);

  // Modals
  const [createModal, setCreateModal]     = useState(false);
  const [enrollModal, setEnrollModal]     = useState(null);  // batch object
  const [courseModal, setCourseModal]     = useState(null);  // batch object
  const [feeModal, setFeeModal]           = useState(null);  // batch object

  const [form, setForm]         = useState({ name: "", department: "", startDate: "", endDate: "" });
  const [selectedStudents, setSelectedStudents] = useState([]);
  const [selectedCourse, setSelectedCourse]     = useState("");
  const [feeForm, setFeeForm]   = useState({ amount: "", dueDate: "", description: "", feeType: "TUITION" });
  const [saving, setSaving]     = useState(false);

  const load = () => {
    setLoading(true);
    Promise.all([getAllBatches(), getAllDepartments(), getAllStudents(), getAllCourses()])
      .then(([b, d, s, c]) => {
        setBatches(Array.isArray(b) ? b : []);
        setDepts(Array.isArray(d) ? d.filter(x => x.active) : []);
        setAllStudents(Array.isArray(s) ? s : []);
        setAllCourses(Array.isArray(c) ? c : []);
      })
      .catch(console.error).finally(() => setLoading(false));
  };
  useEffect(() => { load(); }, []);

  // ── Create batch ──────────────────────────────────────────────────────────
  const handleCreate = async () => {
    if (!form.name || !form.department || !form.startDate || !form.endDate) { alert("All fields are required."); return; }
    try {
      const created = await createBatch(form);
      setBatches(b => [...b, created]);
      setCreateModal(false);
      setForm({ name: "", department: "", startDate: "", endDate: "" });
    } catch (err) { alert("Error: " + err.message); }
  };

  const handleDelete = async (id) => {
    if (!confirmAction("Delete this batch?")) return;
    await deleteBatch(id).catch(console.error);
    setBatches(b => b.filter(x => x.id !== id));
  };

  // ── Enroll students ───────────────────────────────────────────────────────
  const openEnroll = (batch) => {
    setEnrollModal(batch);
    setSelectedStudents([]);
  };
  const toggleStudent = (id) => setSelectedStudents(prev =>
    prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
  );
  const handleEnroll = async () => {
    if (selectedStudents.length === 0) { alert("Select at least one student."); return; }
    try {
      setSaving(true);
      await addStudentsToBatch(enrollModal.id, selectedStudents);
      alert(`${selectedStudents.length} student(s) added to ${enrollModal.name}!`);
      setEnrollModal(null);
      load();
    } catch (err) { alert("Error: " + err.message); }
    finally { setSaving(false); }
  };

  // ── Assign course ─────────────────────────────────────────────────────────
  const openCourse = (batch) => { setCourseModal(batch); setSelectedCourse(batch.course?.id ? String(batch.course.id) : ""); };
  const handleAssignCourse = async () => {
    try {
      setSaving(true);
      await assignCourseToBatch(courseModal.id, selectedCourse ? Number(selectedCourse) : null);
      alert("Course assigned!");
      setCourseModal(null);
      load();
    } catch (err) { alert("Error: " + err.message); }
    finally { setSaving(false); }
  };

  // ── Generate fees for batch ───────────────────────────────────────────────
  const openFee = (batch) => { setFeeModal(batch); setFeeForm({ amount: "", dueDate: "", description: "", feeType: "TUITION" }); };
  const handleGenerateFees = async () => {
    if (!feeForm.amount || !feeForm.dueDate) { alert("Amount and due date required."); return; }
    // Get students in this batch from the already-loaded data
    const batchStudents = enrollModal?.students || feeModal?.students || [];
    if (batchStudents.length === 0) { alert("No students in this batch yet. Add students first."); return; }
    try {
      setSaving(true);
      let count = 0;
      for (const s of batchStudents) {
        await createFee({
          studentId:   s.id,
          amount:      feeForm.amount,
          dueDate:     feeForm.dueDate,
          description: feeForm.description || `${feeModal.name} - ${feeForm.feeType}`,
          feeType:     feeForm.feeType,
          department:  feeModal.department,
          batchId:     feeModal.id,
          courseId:    feeModal.course?.id || undefined,
        });
        count++;
      }
      alert(`✅ Fee generated for ${count} students in ${feeModal.name}`);
      setFeeModal(null);
    } catch (err) { alert("Error: " + err.message); }
    finally { setSaving(false); }
  };

  // Students NOT yet in a specific batch (for enrollment modal)
  const getUnenrolledStudents = (batch) => {
    const enrolled = new Set((batch?.students || []).map(s => s.id));
    return allStudents.filter(s => !enrolled.has(s.id));
  };

  return (
    <div className="fade-up">
      <PageHeader title="Batch Management"
        subtitle="Create batches → Add students → Assign course → Generate fees"
        actions={[
          <Btn variant="ghost" onClick={() => syncBatchStatuses().then(() => load()).catch(console.error)}>🔄 Sync Status</Btn>,
          <Btn variant="primary" onClick={() => setCreateModal(true)}>+ Create Batch</Btn>
        ]} />

      {loading
        ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        : batches.length === 0
          ? <Card><div style={{ padding: 32, textAlign: "center", color: T.muted }}>No batches yet. Create one to get started.</div></Card>
          : <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 20 }}>
              {batches.map(b => {
                const studentCount = b.students?.length ?? 0;
                const hasC = !!b.course;
                return (
                  <Card key={b.id} style={{ padding: 22 }}>
                    {/* Header */}
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                      <div>
                        <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 15 }}>{b.name}</div>
                        <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>🏢 {b.department}</div>
                      </div>
                      <Badge type={b.status === "ACTIVE" ? "success" : b.status === "UPCOMING" ? "info" : "warning"}>{b.status || "UPCOMING"}</Badge>
                    </div>

                    {/* Stats row */}
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 12 }}>
                      {[
                        ["👥 Students", studentCount, studentCount > 0 ? T.accentG : T.muted],
                        ["📚 Course", hasC ? b.course.title : "Not assigned", hasC ? T.accent : T.muted],
                        ["📅 Start", b.startDate || "—", T.muted],
                        ["📅 End",   b.endDate   || "—", T.muted],
                      ].map(([l, v, c]) => (
                        <div key={l} style={{ background: T.bg3, borderRadius: 8, padding: "8px 10px" }}>
                          <div style={{ fontSize: 10, color: T.muted, marginBottom: 2 }}>{l}</div>
                          <div style={{ fontSize: 12, fontWeight: 700, color: c, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{String(v)}</div>
                        </div>
                      ))}
                    </div>

                    {/* Action buttons */}
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginBottom: 6 }}>
                      <Btn size="xs" variant="primary" onClick={() => openEnroll(b)}>👥 Add Students</Btn>
                      <Btn size="xs" variant="dark"    onClick={() => openCourse(b)}>📚 Assign Course</Btn>
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
                      <Btn size="xs" variant="success" onClick={() => openFee(b)}
                        disabled={studentCount === 0}
                        style={{ opacity: studentCount === 0 ? 0.5 : 1 }}>
                        💳 Generate Fees
                      </Btn>
                      <Btn size="xs" variant="danger" onClick={() => handleDelete(b.id)}>🗑 Delete</Btn>
                    </div>
                  </Card>
                );
              })}
            </div>
      }

      {/* ── Create Batch Modal ── */}
      <Modal open={createModal} onClose={() => setCreateModal(false)} title="Create New Batch">
        <p style={{ fontSize: 13, color: T.muted, marginBottom: 14 }}>
          After creating a batch: add students → assign a course → generate fees.
        </p>
        <Input label="Batch Name *" placeholder="e.g. CS-2026-Batch-A" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} />
        <Select label="Department *" value={form.department} onChange={e => setForm(f => ({ ...f, department: e.target.value }))}
          options={[{ value: "", label: "-- Select Department --" }, ...depts.map(d => ({ value: d.name, label: d.name }))]} />
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Input label="Start Date *" type="date" value={form.startDate} onChange={e => setForm(f => ({ ...f, startDate: e.target.value }))} />
          <Input label="End Date *"   type="date" value={form.endDate}   onChange={e => setForm(f => ({ ...f, endDate: e.target.value }))} />
        </div>
        <Btn variant="primary" full size="lg" onClick={handleCreate}>Create Batch →</Btn>
      </Modal>

      {/* ── Enroll Students Modal ── */}
      <Modal open={!!enrollModal} onClose={() => setEnrollModal(null)} title={`Add Students → ${enrollModal?.name}`}>
        <p style={{ fontSize: 13, color: T.muted, marginBottom: 14 }}>
          Batch department: <strong>{enrollModal?.department}</strong> · Currently enrolled: <strong>{enrollModal?.students?.length ?? 0}</strong>
        </p>
        {/* Filter to show same-department students first */}
        {(() => {
          const unenrolled = getUnenrolledStudents(enrollModal);
          const sameDept   = unenrolled.filter(s => s.department === enrollModal?.department);
          const otherDept  = unenrolled.filter(s => s.department !== enrollModal?.department);
          const toShow     = [...sameDept, ...otherDept];
          if (toShow.length === 0) return <div style={{ padding: 16, textAlign: "center", color: T.muted }}>All students already enrolled.</div>;
          return (
            <>
              <div style={{ fontSize: 11, color: T.muted, marginBottom: 8 }}>
                {selectedStudents.length} selected · {sameDept.length} from {enrollModal?.department}
              </div>
              <div style={{ maxHeight: 300, overflowY: "auto", border: `1px solid ${T.border}`, borderRadius: 9, marginBottom: 14 }}>
                {toShow.map(s => {
                  const checked = selectedStudents.includes(s.id);
                  return (
                    <div key={s.id} onClick={() => toggleStudent(s.id)}
                      style={{ display: "flex", gap: 12, padding: "10px 14px", cursor: "pointer", borderBottom: `1px solid rgba(45,33,96,.3)`,
                        background: checked ? `${T.primary}18` : "transparent", transition: "background .15s" }}>
                      <div style={{ width: 18, height: 18, borderRadius: 4, border: `2px solid ${checked ? T.primary : T.border}`,
                        background: checked ? T.primary : "transparent", display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 11, color: "#fff", flexShrink: 0 }}>
                        {checked && "✓"}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 13, fontWeight: 600 }}>{s.name}</div>
                        <div style={{ fontSize: 11, color: T.muted }}>{s.userId} · {s.department || "No dept"}</div>
                      </div>
                      {s.department === enrollModal?.department &&
                        <span style={{ fontSize: 10, color: T.accentG, fontWeight: 700 }}>✓ Same dept</span>}
                    </div>
                  );
                })}
              </div>
            </>
          );
        })()}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
          <Btn variant="ghost" onClick={() => {
            const unenrolled = getUnenrolledStudents(enrollModal);
            const sameDept = unenrolled.filter(s => s.department === enrollModal?.department);
            setSelectedStudents(sameDept.map(s => s.id));
          }}>Select Same Dept</Btn>
          <Btn variant="primary" onClick={handleEnroll} disabled={saving || selectedStudents.length === 0}>
            {saving ? "Adding…" : `Add ${selectedStudents.length} Student(s) →`}
          </Btn>
        </div>
      </Modal>

      {/* ── Assign Course Modal ── */}
      <Modal open={!!courseModal} onClose={() => setCourseModal(null)} title={`Assign Course → ${courseModal?.name}`}>
        <p style={{ fontSize: 13, color: T.muted, marginBottom: 14 }}>
          Students in this batch will see the assigned course in their dashboard.
        </p>
        {courseModal?.course && (
          <div style={{ background: `${T.accentG}15`, border: `1px solid ${T.accentG}30`, borderRadius: 9, padding: "10px 14px", marginBottom: 14, fontSize: 13 }}>
            ✅ Current course: <strong>{courseModal.course.title}</strong>
          </div>
        )}
        <Select label="Select Course *" value={selectedCourse} onChange={e => setSelectedCourse(e.target.value)}
          options={[
            { value: "", label: "-- None (remove assignment) --" },
            ...allCourses
              .filter(c => !courseModal?.department || c.department === courseModal?.department || !c.department)
              .map(c => ({ value: String(c.id), label: `${c.title} (${c.department || "All"}) — ${c.teacher?.name || "No teacher"}` }))
          ]} />
        {allCourses.filter(c => c.department === courseModal?.department).length === 0 && (
          <div style={{ fontSize: 12, color: T.accentY, marginBottom: 14 }}>
            ⚠️ No courses in "{courseModal?.department}" department. Create a course first.
          </div>
        )}
        <Btn variant="primary" full onClick={handleAssignCourse} disabled={saving}>
          {saving ? "Saving…" : "Assign Course →"}
        </Btn>
      </Modal>

      {/* ── Generate Fees Modal ── */}
      <Modal open={!!feeModal} onClose={() => setFeeModal(null)} title={`Generate Fees → ${feeModal?.name}`}>
        <div style={{ background: T.bg3, borderRadius: 9, padding: "10px 14px", marginBottom: 14 }}>
          <div style={{ fontSize: 12, color: T.muted }}>This will create individual fee records for each student in this batch.</div>
          <div style={{ marginTop: 8, display: "flex", gap: 12, fontSize: 13 }}>
            <span>👥 <strong>{feeModal?.students?.length ?? 0}</strong> students</span>
            <span>🏢 <strong>{feeModal?.department}</strong></span>
            {feeModal?.course && <span>📚 <strong>{feeModal.course.title}</strong></span>}
          </div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Input label="Amount (₹) *" type="number" placeholder="e.g. 15000" value={feeForm.amount}
            onChange={e => setFeeForm(f => ({ ...f, amount: e.target.value }))} />
          <Input label="Due Date *" type="date" value={feeForm.dueDate}
            onChange={e => setFeeForm(f => ({ ...f, dueDate: e.target.value }))} />
        </div>
        <Input label="Description" placeholder="e.g. Tuition Fee Q1" value={feeForm.description}
          onChange={e => setFeeForm(f => ({ ...f, description: e.target.value }))} />
        <Select label="Fee Type" value={feeForm.feeType} onChange={e => setFeeForm(f => ({ ...f, feeType: e.target.value }))}
          options={["TUITION", "EXAM", "LAB", "LIBRARY", "TRANSPORT", "MISCELLANEOUS"].map(o => ({ value: o, label: o }))} />
        <div style={{ background: `${T.accentY}15`, border: `1px solid ${T.accentY}30`, borderRadius: 9, padding: "10px 14px", marginBottom: 14, fontSize: 13 }}>
          💳 Will generate <strong>{feeModal?.students?.length ?? 0}</strong> fee records of <strong>₹{feeForm.amount || "0"}</strong> each
          = <strong>₹{((feeModal?.students?.length ?? 0) * Number(feeForm.amount || 0)).toLocaleString("en-IN")}</strong> total
        </div>
        <Btn variant="primary" full size="lg" onClick={handleGenerateFees} disabled={saving || !feeForm.amount || !feeForm.dueDate}>
          {saving ? "Generating…" : `Generate Fees for ${feeModal?.students?.length ?? 0} Students →`}
        </Btn>
      </Modal>
    </div>
  );
};

